wline;insoptiwrth "safe" -ForegroundColor blue -NoNewline;insoptiwrth ", " -ForegroundColor White -NoNewline;insoptiwrth "efficient" -ForegroundColor Cyan -NoNewline;insoptiwrth ", and " -ForegroundColor White -NoNewline;insoptiwrth "fully reversible" -ForegroundColor Blue -NoNewline;insoptiwrth "." -ForegroundColor White;insoptiwrth " ";insoptiwrth "                    Note: in some cases, your game may refuse to launch or display an error on startup." -ForegroundColor Yellow;insoptiwrth "               This is caused by 'runasadmin optimization' for some users, the game can may refuse to launch." -ForegroundColor Yellow;Write-Output "";insoptiwrth " ‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗‗" -ForegroundColor DarkGray;Write-Output ""};insoptibanner;Write-Output "";$insoptimsg="                                              Press any key to continue..";insoptiwrth $insoptimsg -NoNewline;$host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")|Out-Null;$insoptipos=$host.UI.RawUI.CursorPosition;$host.UI.RawUI.CursorPosition=@{X=0;Y=$insoptipos.Y};insoptiwrth (" "*$insoptimsg.Length) -NoNewline;$host.UI.RawUI.CursorPosition=@{X=0;Y=$insoptipos.Y};Get-Process|Where-Object{$_.ProcessName -like "FiveM*"}|ForEach-Object{Stop-Process -Id $_.Id -Force};$insoptiperf,$insoptiQoS,$insoptigpu='HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options\FiveM_GTAProcess.exe\PerfOptions','HKLM:\SOFTWARE\Policies\Microsoft\Windows\QoS\FiveM_GTAProcess.exe','HKCU:\SOFTWARE\Microsoft\DirectX\UserGpuPreferences'
function insoptiGetFiveMExe {$insoptidefaultPath="$env:LOCALAPPDATA\FiveM\FiveM.app\data\cache\subprocess\FiveM_GTAProcess.exe";if(Test-Path $insoptidefaultPath){return $insoptidefaultPath};$insoptiroots=Get-PSDrive -PSProvider FileSystem|ForEach-Object{$_.Root};$insoptipaths=foreach($r in $insoptiroots){"${r}FiveM\FiveM.app\data\cache\subprocess\FiveM_GTAProcess.exe"};$insoptipaths|Where-Object{Test-Path $_}|Select-Object -First 1}
