function insoptiApplyPerfOptions {;try {;New-Item -Path $insoptiperf -Force|Out-Null;@{'CpuPriorityClass'=3;'IoPriority'=3}.GetEnumerator()|ForEach-Object{New-ItemProperty -Path $insoptiperf -Name $_.Key -Value $_.Value -PropertyType DWord -Force|Out-Null};insoptiwrth "[" -NoNewline -ForegroundColor White;insoptiwrth "+" -NoNewline -ForegroundColor Green;insoptiwrth "] " -NoNewline -ForegroundColor White;insoptiwrth "Successfully" -NoNewline -ForegroundColor Green;insoptiwrth " set CPU & I/O priority to " -NoNewline -ForegroundColor White;insoptiwrth "High" -NoNewline -ForegroundColor Green;insoptiwrth ", Allocates more system resources to FiveM in foreground." -ForegroundColor White} catch {insoptiwh "Failed to configure performance options." "error"}}
function insoptiApplyQoS {;try {$insoptiFiveMexe=insoptiGetFiveMExe;if(-not $insoptiFiveMexe){insoptiwh "FiveM executable not found." "error";return};if(-not([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)){insoptiwh "ApplyQoS requires administrator rights." "error";return};New-Item -Path $insoptiQoS -Force -ErrorAction Stop|Out-Null;@{'Application Name'='FiveM_GTAProcess.exe';'AppPathName'=$insoptiFiveMexe;'DSCP Value'='46';'Local IP'='*';'Local IP Prefix Length'='*';'Local Port'='*';'Protocol'='*';'Remote IP'='*';'Remote IP Prefix Length'='*';'Remote Port'='*';'Throttle Rate'='-1';'Version'='1.0'}.GetEnumerator()|ForEach-Object{New-ItemProperty -Path $insoptiQoS -Name $_.Key -Value $_.Value -PropertyType String -Force -ErrorAction Stop|Out-Null};insoptiwh "Successfully created a QoS rules and set DSCP 46 (EF) with ThrottleRate disabled for prioritized network traffic." "success"}catch{insoptiwh "QoS creation error: $($_.Exception.Message)" "error"}}
function insoptiApplyGPU {;try {;if(-not(Test-Path $insoptigpu)){New-Item -Path $insoptigpu -ItemType Directory|Out-Null};$insoptiFiveMexe=insoptiGetFiveMExe;if(-not $insoptiFiveMexe){insoptiwh "FiveM executable not found." "error";return};New-ItemProperty -Path $insoptigpu -Name $insoptiFiveMexe -Value 'GpuPreference=2' -PropertyType String -Force|Out-Null;insoptiwrth "[" -NoNewline -ForegroundColor White;insoptiwrth "+" -NoNewline -ForegroundColor Green;insoptiwrth "] " -NoNewline -ForegroundColor White;insoptiwrth "Successfully" -NoNewline -ForegroundColor Green;insoptiwrth " set GPU preference to " -NoNewline -ForegroundColor White;insoptiwrth "High Performance" -NoNewline -ForegroundColor Green;insoptiwrth ", in Windows Settings." -ForegroundColor White}catch{insoptiwh "GPU configuration error." "error"}}
function insoptiApplyRunAsAdmin {;try {;$insoptiFiveMexe=insoptiGetFiveMExe;if(-not $insoptiFiveMexe){insoptiwh "FiveM executable not found." "error";return};New-ItemProperty -Path "HKCU:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\AppCompatFlags\Layers" -Name $insoptiFiveMexe -Value "~ RUNASADMIN" -PropertyType String -Force|Out-Null;$insoptiifeopath="HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options\FiveM_GTAProcess.exe";if(-not(Test-Path $insoptiifeopath)){New-Item -Path $insoptiifeopath -Force|Out-Null};New-ItemProperty -Path $insoptiifeopath -Name "RunAsAdmin" -Value 1 -PropertyType DWord -Force|Out-Null;insoptiwrth "[" -NoNewline -ForegroundColor White;insoptiwrth "+" -NoNewline -ForegroundColor Green;insoptiwrth "] " -NoNewline -ForegroundColor White;insoptiwrth "Successfully" -NoNewline -ForegroundColor Green;insoptiwrth " configured FiveM to run as " -NoNewline -ForegroundColor White;insoptiwrth "Administrator" -NoNewline -ForegroundColor Green;insoptiwrth ", Grants elevated privileges for better compatibility." -ForegroundColor White}catch{insoptiwh "Error configuring administrator privileges." "error"}}
function insoptiApplyFirewall {;try {;$insoptiFiveMexe=insoptiGetFiveMExe;if(-not $insoptiFiveMexe){return insoptiwh "FiveM executable not found." "error"};"In","Out"|ForEach-Object{New-NetFirewallRule -DisplayName "FiveMClient ($_)" -Direction "${_}bound" -Program $insoptiFiveMexe -Action Allow -ErrorAction SilentlyContinue|Out-Null};insoptiwrth "[" -NoNewline -ForegroundColor White;insoptiwrth "+" -NoNewline -ForegroundColor Green;insoptiwrth "] " -NoNewline -ForegroundColor White;insoptiwrth "Successfully" -NoNewline -ForegroundColor Green;insoptiwrth " added firewall rules " -NoNewline -ForegroundColor White;insoptiwrth "Inbound & Outbound" -NoNewline -ForegroundColor Green;insoptiwrth ", Prevents connection blocking and packet loss." -ForegroundColor White}catch{insoptiwh "Firewall configuration error: $($_.Exception.Message)" "error"}}
function insoptiApplyDefender {;try {;$insoptiFiveMdir=insoptiGetFiveMDir;if(-not(Test-Path $insoptiFiveMdir)){return insoptiwh "FiveM directory not found." "error"};Add-MpPreference -ExclusionPath $insoptiFiveMdir -ErrorAction SilentlyContinue;if($?){insoptiwrth "[" -NoNewline -ForegroundColor White;insoptiwrth "+" -NoNewline -ForegroundColor Green;insoptiwrth "] " -NoNewline -ForegroundColor White;insoptiwrth "Successfully" -NoNewline -ForegroundColor Green;insoptiwrth " added Windows Defender " -NoNewline -ForegroundColor White;insoptiwrth "Exclusion" -NoNewline -ForegroundColor Green;insoptiwrth ", Prevents background scans from impacting performance." -ForegroundColor White}else{insoptiwh "Windows Defender exclusion could not be applied." "warning"}}catch{insoptiwh "Error Defednder exclusion: Windows Defender is disabled or unavailable on this system. No changes have been made." "error"}}
function insoptiRemoveAll {;try{if(Test-Path $insoptiperf){Remove-Item $insoptiperf -Recurse -Force};insoptiwrth "[" -NoNewline -ForegroundColor White;insoptiwrth "+" -NoNewline -ForegroundColor Yellow;insoptiwrth "] " -NoNewline -ForegroundColor White;insoptiwrth "Successfully" -NoNewline -ForegroundColor Yellow;insoptiwrth " removed CPU & I/O priority, Restored to " -NoNewline -ForegroundColor White;insoptiwrth "Normal" -NoNewline -ForegroundColor Cyan;insoptiwrth " default priority." -ForegroundColor White}catch{insoptiwh "Error removing performance options." "error"}
