try{Remove-NetFirewallRule -DisplayName "FiveMClient (In)" -ErrorAction SilentlyContinue;Remove-NetFirewallRule -DisplayName "FiveMClient (Out)" -ErrorAction SilentlyContinue;insoptiwrth "[" -NoNewline -ForegroundColor White;insoptiwrth "+" -NoNewline -ForegroundColor Yellow;insoptiwrth "] " -NoNewline -ForegroundColor White;insoptiwrth "Successfully" -NoNewline -ForegroundColor Yellow;insoptiwrth " removed firewall rules, Custom rules " -NoNewline -ForegroundColor White;insoptiwrth "Deleted" -NoNewline -ForegroundColor Cyan;insoptiwrth "." -ForegroundColor White}catch{insoptiwh "Error removing firewall rules." "error"}
try{$insoptiFiveMdir=insoptiGetFiveMDir;if($insoptiFiveMdir){Remove-MpPreference -ExclusionPath $insoptiFiveMdir -ErrorAction SilentlyContinue};insoptiwrth "[" -NoNewline -ForegroundColor White;insoptiwrth "+" -NoNewline -ForegroundColor Yellow;insoptiwrth "] " -NoNewline -ForegroundColor White;insoptiwrth "Successfully" -NoNewline -ForegroundColor Yellow;insoptiwrth " removed Defender exclusion, Folder protection " -NoNewline -ForegroundColor White;insoptiwrth "'Re-enabled'" -NoNewline -ForegroundColor Cyan;insoptiwrth "." -ForegroundColor White}catch{insoptiwh "Error removing Defender exclusion. Windows Defender is disabled or unavailable on this system." "error"}
